INSERT INTO public.wiki_pages (id, room_id, title, content, parent_id, created_at, updated_at) VALUES ('a55b7482-2288-43e9-a482-4561e440ed4a', 'c3497459-c4bf-4a9e-a01e-032f1a3f4df0', 'Pan, Astræus & Moiræ', '<p>Tres poderosas deidades influyen sobre las fuerzas que dan forma a la existencia misma.</p><p><br></p><p>Pan, el dios del Orden Natural, la Civilización y la Ley, encarna la armonía y el equilibrio del mundo. Es venerado por aquellos que buscan estabilidad, estructura y la suave guía de los ritmos de la naturaleza. La influencia de Pan se siente en los bosques frondosos, los ríos que fluyen y las bulliciosas ciudades donde la ley y el orden prevalecen.</p><p><br></p><p>Por otro lado, se encuentra Astraeus, el dios del Caos, las Estrellas y la Magia. Es una fuerza indomable, que representa las corrientes cambiantes del cosmos. Los seguidores de Astraeus se sienten atraídos por los misterios del cielo nocturno, la magia impredecible que corre por sus venas y la belleza caótica de un mundo sin restricciones ni límites.</p><p><br></p><p>Entre estas dos fuerzas opuestas se encuentra Moirae, la diosa del Destino y la Neutralidad. Es la tejedora del destino, imparcial e inflexible en su juicio. El dominio de Moirae es el tapiz de la existencia misma, donde cada hilo representa una vida y cada decisión da forma al curso de la historia. Aunque permanece neutral entre Pan y Astraeus, su influencia se siente por todos los que recorren los caminos del mundo.</p><p><br></p><p><strong>Pan</strong></p><p><br></p><p><br></p><p><img src="data:image/jpeg;base64,"></p><p><strong>Astræus</strong></p><p><img src="data:image/jpeg;base64,"></p><p><strong>Moiræ</strong></p><p><img src="data:image/jpeg;base64,"></p>', '0c12d0a6-9f25-4d34-a65f-3c37d904974e', '2025-08-31 15:42:20.937228', '2025-08-31 15:44:39.809');

